param([string]$Decision="DEFER",[bool]$HumanConfirmation=$false,[bool]$ExecutionAllowed=$false);$ErrorActionPreference="Stop";$approved=($Decision -eq "APPROVE" -and $HumanConfirmation -eq $true -and $ExecutionAllowed -eq $true);$result=[ordered]@{decision=$Decision;human_confirmation=$HumanConfirmation;execution_allowed=$ExecutionAllowed;approved=$approved;gate=if($approved){"APPROVE"}else{"DEFER"};apply_executed=$false;auto_apply=$false;remote_execution=$false;git_write=$false;status=if($approved){"GATE_APPROVED_NO_AUTO_APPLY"}else{"BLOCKED_BY_GATE"}};$result|ConvertTo-Json -Depth 10
